//! Canonical metadata for the SoraFS gateway fixtures (SF-5a).
//!
//! The fixture bundle itself is generated by the integration test harness to
//! avoid a dependency cycle between `sorafs_manifest` and `sorafs_car`. This
//! module exposes the published metadata so runtime components can validate the
//! bundle released for the trustless gateway profile.

/// Semantic version string for the published gateway fixture bundle.
pub const SORAFS_GATEWAY_FIXTURE_VERSION: &str = "1.0.0";

/// Gateway profile identifier covered by the canonical bundle.
pub const SORAFS_GATEWAY_PROFILE_VERSION: &str = "sf1";

/// Release timestamp (seconds since the UNIX epoch) for the bundle.
pub const SORAFS_GATEWAY_FIXTURE_RELEASE_UNIX: u64 = 1_770_854_400;

/// Aggregated BLAKE3 digest (hex) covering the canonical fixture bundle.
pub const SORAFS_GATEWAY_FIXTURE_DIGEST_HEX: &str =
    "fa5bcbc0776fcc762c6df13b0dfa8ad15673fd65509f505ea3ea0f0ffab32cdf";

/// Canonical manifest payload digest (hex).
pub const SORAFS_GATEWAY_MANIFEST_DIGEST_HEX: &str =
    "ecc2e8564dda27834b8bd53a3eebdc56055d3e2cbdd30b0f96938fb9f04b216e";

/// Canonical deterministic payload digest (hex).
pub const SORAFS_GATEWAY_PAYLOAD_DIGEST_HEX: &str =
    "91275991d58858bdc7ce3eb4472b61c5289dec3ecc6cf43c6411db772c1888a8";

/// Canonical CAR payload digest (hex).
pub const SORAFS_GATEWAY_CAR_DIGEST_HEX: &str =
    "ce50a9aadf84e57559208d39201621262fd1b1887ae490ca54470e2a00153f27";

/// Metadata snapshot describing the canonical gateway fixtures.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct GatewayFixtureMetadata {
    /// Semantic version string for the published fixture bundle.
    pub version: &'static str,
    /// Profile identifier validated by the bundle.
    pub profile_version: &'static str,
    /// Release timestamp (seconds since the UNIX epoch).
    pub released_at_unix: u64,
    /// Aggregated BLAKE3 digest covering the fixture contents (hex encoded).
    pub fixtures_digest_blake3_hex: &'static str,
    /// BLAKE3 digest of the manifest payload (hex encoded).
    pub manifest_blake3_hex: &'static str,
    /// BLAKE3 digest of the deterministic payload (hex encoded).
    pub payload_blake3_hex: &'static str,
    /// BLAKE3 digest of the CAR payload (hex encoded).
    pub car_blake3_hex: &'static str,
}

impl GatewayFixtureMetadata {
    /// Short helper exposing the aggregated digest as `&str`.
    #[must_use]
    pub const fn digest_hex(&self) -> &'static str {
        self.fixtures_digest_blake3_hex
    }
}

/// Return the canonical gateway fixture metadata.
#[must_use]
pub const fn gateway_fixture_metadata() -> GatewayFixtureMetadata {
    GatewayFixtureMetadata {
        version: SORAFS_GATEWAY_FIXTURE_VERSION,
        profile_version: SORAFS_GATEWAY_PROFILE_VERSION,
        released_at_unix: SORAFS_GATEWAY_FIXTURE_RELEASE_UNIX,
        fixtures_digest_blake3_hex: SORAFS_GATEWAY_FIXTURE_DIGEST_HEX,
        manifest_blake3_hex: SORAFS_GATEWAY_MANIFEST_DIGEST_HEX,
        payload_blake3_hex: SORAFS_GATEWAY_PAYLOAD_DIGEST_HEX,
        car_blake3_hex: SORAFS_GATEWAY_CAR_DIGEST_HEX,
    }
}

/// Return the aggregated fixture digest (hex).
#[must_use]
pub const fn gateway_fixture_digest_hex() -> &'static str {
    SORAFS_GATEWAY_FIXTURE_DIGEST_HEX
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn metadata_exposes_constants() {
        let metadata = gateway_fixture_metadata();
        assert_eq!(metadata.version, SORAFS_GATEWAY_FIXTURE_VERSION);
        assert_eq!(metadata.profile_version, SORAFS_GATEWAY_PROFILE_VERSION);
        assert_eq!(
            metadata.released_at_unix,
            SORAFS_GATEWAY_FIXTURE_RELEASE_UNIX
        );
        assert_eq!(metadata.digest_hex(), SORAFS_GATEWAY_FIXTURE_DIGEST_HEX);
    }
}
